// Command seed pre-populates the MySQL database with the official account and a
// set of sample blueprints. Idempotent: re-running won't duplicate entries.
//
// Usage: cd backend-go && go run ./cmd/seed
package main

import (
	"log"
	"os"
	"strings"

	"brickplans/internal/auth"
	"brickplans/internal/config"
	"brickplans/internal/db"
)

var (
	nonAlphaNumDash = strings.NewReplacer(" ", "-")
)

type seedBP struct {
	Title       string
	Category    string
	Difficulty  int
	PieceCount  int
	Description string
}

var seedBlueprints = []seedBP{
	{"中世纪城堡", "建筑", 4, 3200, "# 中世纪城堡\n\n## 搭建难度：⭐⭐⭐⭐（中高级，3200零件）\n\n这座经典的欧式中世纪城堡是野心之作——3200个零件的庞大体量，从城墙到塔楼再到吊桥，全结构还原。搭建过程需要合理安排搭建顺序，先主体结构后细节装饰，建议分模块完成。灰色砖块是绝对主力，深灰和棕色零件用于点缀城墙纹理和木质结构。零件种类涵盖大量基础砖、斜坡砖、圆柱和拱形件，对玩家的零件分类和结构理解能力有一定要求。\n\n## 零件特色\n\n- 大量灰色系基础砖，用于搭建城墙和塔楼主体\n- 深灰色和棕色点缀件，模拟石墙纹理和木结构\n- 特殊件：城堡垛口、拱形门洞、吊桥链条\n- 人仔配件：骑士、盾牌、旗帜\n\n## 成品展示\n\n完成后的城堡高约35cm，占地约40×30cm，是当之无愧的桌面镇宅之宝。城墙可分段拆卸展示内部结构，吊桥可通过链条机关手动升降，四座塔楼顶部均可放置人仔。搭配几个骑士人仔和旗帜，瞬间穿越回中世纪战场。\n\n## 适合人群\n\n有3-5款中型套装搭建经验的中高级玩家，喜欢大型建筑展示、追求细节还原度的\"城堡控\"。如果你是第一次尝试3000+零件的挑战，建议从城墙模块开始，逐步建立信心。"},
	{"现代别墅", "建筑", 3, 1800, "# 现代别墅\n\n## 搭建难度：⭐⭐⭐（中级，1800零件）\n\n极简主义爱好者的梦想之作——1800个零件打造出一座现代风格的独栋别墅。搭建节奏适中，主体结构清晰，没有复杂的拼装技巧，更注重线条感和配色搭配。白色外墙搭配大面积玻璃幕墙，再用深灰线条勾勒建筑轮廓，整体风格干净利落。适合有一定搭建经验、正在向大型作品过渡的玩家。\n\n## 零件特色\n\n- 白色平板砖和光面板为主，营造简约外墙\n- 透明蓝色/透明零件模拟玻璃幕墙和落地窗\n- 浅灰色台阶和深灰色屋顶线条\n- 绿色基础板用于花园底座\n- 特殊件：圆形泳池、窗户框架、植物零件\n\n## 成品展示\n\n成品别墅占地约30×25cm，一层为客厅+开放式厨房，二层为卧室+阳台。室外配有小花园、泳池和休闲椅，可直接融入城市街景系列。白色外墙在灯光下质感出众，落地窗设计让内部空间一目了然，拍照效果极佳。\n\n## 适合人群\n\n喜欢现代建筑风格、正在打造城市街景的玩家。中等难度，3-4小时即可完成，非常适合周末搭建。如果你有多个街景作品，这款别墅可以作为街景系列的点睛之笔。"},
	{"日式神社", "建筑", 3, 1500, "# 日式神社\n\n## 搭建难度：⭐⭐⭐（中级，1500零件）\n\n1500个零件重现传统日式神社的静谧之美。搭建难度适中，但屋顶部分需要特别的耐心——层层叠叠的飞檐屋顶是整座神社的灵魂，也是搭建中最考验耐心的部分。红色鸟居是标志性入口，主殿采用深棕色木结构配合白色墙面，还原度极高。适合中级玩家。\n\n## 零件特色\n\n- 红色零件：大量用于鸟居和主殿立柱，是视觉焦点\n- 深棕色零件：模拟木结构横梁和屋顶框架\n- 白色光面板：用于墙面和台阶\n- 特殊件：屋顶瓦片纹理件、灯笼装饰、石质基座\n- 金色点缀：用于殿内装饰细节\n\n## 成品展示\n\n神社主体高约25cm，包含一个完整的参道布局：入口红色鸟居→参道石阶→主殿→后院。屋顶飞檐微微上翘，还原了日式建筑最标志性的线条。灯笼和石质基座等细节让场景更有沉浸感。搭配樱花或枫树零件，四季皆宜。\n\n## 适合人群\n\n喜欢东方建筑、日式美学和场景搭建的玩家。中级难度，适合有3-5款套装经验的朋友。完成后既可以单独展示，也非常适合搭配日式庭院场景。如果你正在打造亚洲主题街景，这款神社是绝对的主角。"},
	{"太空基地", "建筑", 5, 4500, "# 太空基地\n\n## 搭建难度：⭐⭐⭐⭐⭐（专家级，4500零件）\n\nBrickPlan 目前零件数最多的图纸，4500个零件打造月球表面综合科研基地。搭建难度五颗星，需要合理规划搭建顺序和零件管理策略。建议按功能模块分步搭建：先主控室→生活舱→实验舱→发射台→连接通道。大量白色和浅灰零件构成基地主体，透明蓝色零件模拟能源装置，科技感拉满。\n\n## 零件特色\n\n- 白色和浅灰色基础砖、光面板大量使用，构建科幻感外壳\n- 透明蓝色特殊件：模拟能源核心、太阳能板和发光装置\n- 银色和金属灰零件：用于天线、机械臂和科技设备\n- 特殊件：圆形穹顶、舱门、对接接口、轮式底盘\n- 橙色和红色小零件：点缀警示灯和按钮细节\n\n## 成品展示\n\n基地整体占地约50×40cm，包含主控室（带可开合穹顶）、生活舱（内部有床铺和桌椅）、实验舱（显微镜和培养皿道具）、发射台（可停放小型飞船）和连接通道。月球表面地形使用灰色底板搭建，配以陨石坑装饰。每个舱室均可打开展示内部细节，可玩性极高。\n\n## 适合人群\n\n太空主题爱好者、硬核科幻迷。4500+零件的体量适合有大型套装搭建经验的中高级玩家，建议分3-4天完成。如果你喜欢乐高城市系列太空主题或NASA系列，这套图纸会让你爱不释手。"},
	{"树屋村落", "建筑", 2, 1200, "# 树屋村落\n\n## 搭建难度：⭐⭐（入门，1200零件）\n\n建在巨型树木上的温馨树屋村落，1200个零件即可打造一个充满童话感的森林世界。难度两星，搭建步骤清晰，没有复杂的拼装技巧，非常适合新手玩家入门。棕色和绿色为主色调，吊桥连接各个小屋，整体氛围温暖治愈。\n\n## 零件特色\n\n- 棕色零件：大量用于树干、树枝和木屋墙壁\n- 绿色零件：树叶、树冠和地面植被\n- 深绿色和浅绿色搭配，营造层次感\n- 特殊件：吊桥链条、围栏、梯子、窗户\n- 人仔配件：小桌椅、火把、篮子\n\n## 成品展示\n\n成品含一棵主树（高约30cm）和3间小木屋，由吊桥和梯子相互连接。树冠使用大量绿色零件模拟茂密树叶，小屋内部有简单的家具摆设。完成后可搭配人仔演绎森林生活场景，充满故事感。\n\n## 适合人群\n\n新手玩家、亲子拼搭、喜欢童话和森林主题的大小朋友。搭建难度低，2-3小时即可完成，非常适合作为周末亲子活动。也可以作为儿童房间的装饰品，和孩子一起搭建一个属于自己的树屋王国。"},
	{"F1方程式赛车", "车辆", 3, 950, "# F1方程式赛车\n\n## 搭建难度：⭐⭐⭐（中级，950零件）\n\n950个零件高度还原一台F1方程式赛车，麻雀虽小五脏俱全。搭建难度三星，难点在于空气动力学套件的拼搭和贴纸对齐——前翼、尾翼、侧箱的线条必须精确，否则会影响整体观感。红色涂装经典吸睛，可转动方向盘和可拆卸引擎盖是最吸引人的交互设计。\n\n## 零件特色\n\n- 红色和白色零件为主，还原经典F1涂装\n- 黑色轮胎和轮毂件，F1特有的大尺寸后轮\n- 透明红色尾灯和透明零件\n- 特殊件：F1前翼/尾翼专用件、方向盘、排气管\n- 贴纸：赞助商贴纸、号码牌、仪表盘\n\n## 成品展示\n\n赛车全长约30cm，宽约12cm，忠实还原了真实F1赛车的低趴姿态。前翼和尾翼角度可调，方向盘与前轮联动，引擎盖打开后可以看到V6引擎细节。展示架可调节角度，让赛车呈现赛道飞驰的动感姿态。\n\n## 适合人群\n\n赛车迷、F1粉丝、喜欢机械细节的玩家。950零件的中等体量，2-3小时即可完成。适合作为桌面摆件或车模收藏。如果你喜欢乐高Speed Champions系列，这套图纸的还原度会让你惊喜。"},
	{"重型卡车", "车辆", 4, 2200, "# 重型卡车\n\n## 搭建难度：⭐⭐⭐⭐（中高级，2200零件）\n\n2200个零件打造一台美式重型卡车头，霸气十足。搭建难度四星，底盘结构复杂，需要精确的齿轮传动和转向机构组装。可开启车门、可转向前轮和精致的驾驶室内饰是这款作品的核心亮点。经典的红蓝配色让成品极具辨识度。\n\n## 零件特色\n\n- 红色和蓝色基础砖为主，打造经典美式卡车的涂装\n- 大量科技件（Technic）：用于转向机构、底盘悬架\n- 大尺寸卡车轮胎和轮毂\n- 透明零件：前挡风玻璃、侧窗、车灯\n- 特殊件：后视镜、排气管、保险杠、油箱\n- 镀铬零件：车头格栅、喇叭\n\n## 成品展示\n\n卡车头全长约40cm，高度约25cm，气势磅礴。车门可打开展示内饰细节——方向盘、仪表盘、座椅和卧铺一应俱全。前轮可转向，车头可轻微抬起展示引擎。车身线条流畅，经典涂装让人一秒联想到变形金刚。\n\n## 适合人群\n\n车模爱好者、卡车迷、喜欢机械结构的中高级玩家。2200零件建议3-4小时完成。可搭配拖车和集装箱打造完整运输场景。如果你喜欢乐高Technic系列的机械结构，这款卡车会让你过足搭建瘾。"},
	{"复古摩托车", "车辆", 2, 450, "# 复古摩托车\n\n## 搭建难度：⭐⭐（入门，450零件）\n\n450个零件的Cafe Racer风格复古摩托车，小巧精致但不简单。搭建难度两星，适合新手入门，但细节处理上毫不含糊——棕色皮质座椅、圆形大灯、链条传动，每一个元素都致敬经典机车文化。线条流畅，造型紧凑，成品极具质感。\n\n## 零件特色\n\n- 深棕色零件：模拟皮质座椅和把手\n- 黑色和深灰色零件：引擎、排气管、车轮\n- 银色零件：链条、轮毂、排气口\n- 圆形透明件：前大灯，复古感十足\n- 特殊件：摩托车轮胎、把手、排气管、后视镜\n\n## 成品展示\n\n摩托车全长约15cm，高约10cm，比例精准。车身线条优雅流畅，低矮的Cafe Racer坐姿和简约的车尾设计是最大亮点。前叉可转向，后轮通过链条与引擎联动。展示台上可搭配一个骑士人仔，瞬间有了\"在路上\"的画面感。\n\n## 适合人群\n\n摩托车爱好者、桌面摆件收藏家、新手玩家。450零件30分钟-1小时即可完成，非常适合作为入门作品或午休小项目。如果你喜欢咖啡店风格的机车文化，这款作品会让你爱不释手。"},
	{"挖掘机工程车", "车辆", 3, 1600, "# 挖掘机工程车\n\n## 搭建难度：⭐⭐⭐（中级，1600零件）\n\n功能性挖掘机，1600个零件不仅还原了外观，更实现了真实工程机械的核心功能。搭建难度三星，难点在于液压臂结构的搭建——需要精确的齿轮和连杆配合。液压臂可上下活动，铲斗可开合，履带可转动，可玩性极高。黄色为主色调，黑灰点缀，工程机械感十足。\n\n## 零件特色\n\n- 黄色零件为主，还原工程机械标准涂装\n- 科技件（Technic）：齿轮、连杆、轴、销——用于液压臂和履带传动\n- 黑色橡胶履带件，可灵活转动\n- 灰色和黑色点缀：引擎盖、排气管、驾驶室框架\n- 特殊件：铲斗、液压杆、驾驶室座椅、警示灯\n\n## 成品展示\n\n挖掘机全长约35cm，高约20cm，比例协调。液压臂可多角度调节，最高举升高度约25cm，铲斗可开合，模拟真实挖掘动作。驾驶室可打开，放入人仔后画面感拉满。履带设计使整车可在桌面平稳移动，不是\"只能看不能动\"的静态模型。\n\n## 适合人群\n\n工程车爱好者、喜欢机械传动和可动结构的玩家。中级难度，建议2-3小时完成。如果你喜欢乐高Technic系列的工程机械，这款挖掘机是绝佳的补充。也适合亲子互动——孩子玩铲斗开合，大人搭建机械结构。"},
	{"双层观光巴士", "车辆", 2, 800, "# 双层观光巴士\n\n## 搭建难度：⭐⭐（入门，800零件）\n\n800个零件的伦敦经典红色双层巴士，城市街景的灵魂角色。搭建难度两星，结构清晰，适合新手作为中型作品的第一站。上层和下层内部均有座椅细节，车身广告贴纸可自定义，打造属于你自己的伦敦街景。\n\n## 零件特色\n\n- 红色零件为主，经典的伦敦巴士涂装，醒目大方\n- 透明零件：挡风玻璃、上下层车窗\n- 黑色轮毂和轮胎\n- 特殊件：巴士车门、后视镜、车灯、雨刷\n- 贴纸：车身广告牌、路线号码牌、伦敦标志\n\n## 成品展示\n\n巴士全长约25cm，高约15cm（含上层）。上层为开放式观光座，下层为封闭车厢，内部座椅排列整齐。车门可开关，前轮可转向。车身广告贴纸可自行设计，搭配伦敦电话亭和红色邮筒，一秒穿越到伦敦街头。\n\n## 适合人群\n\n城市街景爱好者、新手玩家、亲子拼搭。800零件1-2小时即可完成，是城市街景系列中最容易上手又最出效果的作品之一。如果你是初次尝试街景系列，建议从这款巴士开始，它能让你快速建立信心。"},
	{"重型突击机甲", "机甲", 5, 3800, "# 重型突击机甲\n\n## 搭建难度：⭐⭐⭐⭐⭐（专家级，3800零件）\n\n武装到牙齿的重型机甲，3800个零件构筑一个移动军火库。搭建难度五星，最大的挑战在于关节结构的稳定性和配重平衡——双肩导弹发射器、右手等离子炮、左手能量盾，每一件武器都会影响机甲的站立姿态。建议从腿部开始搭建，确保底盘稳固后再逐步向上构建躯干和武器系统。\n\n## 零件特色\n\n- 灰色和深灰色零件为主，营造金属装甲质感\n- 科技件（Technic）：大量用于关节连接、齿轮传动和活动机构\n- 红色和橙色点缀：传感器、武器指示灯\n- 特殊件：大型球形关节、导弹发射器、炮管、盾牌面板\n- 透明橙色/红色零件：能量护盾和武器特效\n\n## 成品展示\n\n机甲站立高度约45cm，是真正的\"镇宅级\"作品。双臂可多角度调节，肩部导弹发射器可旋转，等离子炮管可上下摆动。关节可动性极强，可以摆出冲锋、射击、防御等多种战斗姿势。能量盾使用透明橙色零件构成，视觉效果炸裂。\n\n## 适合人群\n\n机甲爱好者、硬核科幻迷、有大型套装搭建经验的高级玩家。3800零件建议分4-5天完成，每天搭建一个模块。如果你喜欢高达、装甲核心等机甲题材，这款作品将是你收藏柜中最耀眼的存在。"},
	{"忍者机甲", "机甲", 3, 1200, "# 忍者机甲\n\n## 搭建难度：⭐⭐⭐（中级，1200零件）\n\n轻量化忍者机甲，1200个零件塑造出灵活敏捷的忍者战士。搭建难度三星，注重可动性和造型美感的平衡。黑红配色经典帅气，双刀和手里剑是标志性武器，背部推进器可展开，实现\"飞行模式\"和\"地面模式\"的双形态切换。\n\n## 零件特色\n\n- 黑色零件为主，构成机甲主体装甲\n- 红色点缀：标志性的忍者面罩和胸甲装饰\n- 灰色关节件：确保四肢可动性\n- 特殊件：忍者刀、手里剑、推进器喷口、头巾飘带\n- 透明红色零件：传感器和能源核心\n\n## 成品展示\n\n机甲高度约25cm，比例紧凑但细节丰富。双臂可360度旋转，双腿可摆出跑步、跳跃等动作，腰部可转动。背部推进器展开后视觉面积增加50%，战斗姿态更加帅气。双刀可手持，手里剑可投掷（取下展示），可玩性极高。\n\n## 适合人群\n\n机甲入门玩家、忍者/武士题材爱好者、喜欢可动展示模型的玩家。中级难度，2-3小时即可完成。如果你第一次尝试机甲类搭建，这款忍者机甲是非常合适的起点——结构简单但效果出色。"},
	{"蒸汽朋克机器人", "机甲", 4, 2100, "# 蒸汽朋克机器人\n\n## 搭建难度：⭐⭐⭐⭐（中高级，2100零件）\n\n维多利亚风格与蒸汽动力的完美结合，2100个零件打造一个充满复古机械美感的机器人。搭建难度四星，黄铜色齿轮、管道和压力表是最大的特色，也是最考验耐心的部分——大量细小零件的堆叠需要精准和细心。左手为多功能工具臂，可更换不同工具头。\n\n## 零件特色\n\n- 黄铜色/金色零件：大量用于齿轮、管道和装饰件，是蒸汽朋克风格的灵魂\n- 棕色和深棕色零件：木制手柄和底座\n- 银色和灰色零件：蒸汽管道、阀门、压力表\n- 特殊件：齿轮（各种尺寸）、管道连接件、钟表表盘、烟囱、锅炉\n- 透明玻璃件：观察窗和仪表盘\n\n## 成品展示\n\n机器人高度约30cm，底座带有一个小型蒸汽锅炉场景。身体内部是一个半开放式的机械结构，齿轮和管道清晰可见，仿佛能看到蒸汽在其中流动。头部带有高礼帽风格的天线，左手工具臂可更换为钳子、扳手或钻头。整体充满了19世纪工业革命的气息。\n\n## 适合人群\n\n蒸汽朋克爱好者、复古机械迷、喜欢细节堆叠的耐心玩家。2100零件建议3-4天完成，适合有中型作品搭建经验的玩家。如果你喜欢《哈尔的移动城堡》或者《天空之城》的机械美学，这款作品会让你爱不释手。"},
	{"动物合体机甲-狮王", "机甲", 4, 2600, "# 动物合体机甲-狮王\n\n## 搭建难度：⭐⭐⭐⭐（中高级，2600零件）\n\n以百兽之王雄狮为原型的合体机甲，2600个零件融合了动物形态的优雅和机甲的刚猛。搭建难度四星，最大的特色是\"变形\"概念——头部鬃毛展开后露出隐藏的武器阵列，四爪可以变换形态，实现从\"雄狮模式\"到\"机甲模式\"的转换。橙金配色霸气十足。\n\n## 零件特色\n\n- 橙色和金色零件为主，还原雄狮的王者气质\n- 深棕色和浅棕色：鬃毛层次感和身体过渡\n- 黄色透明件：能量核心和眼睛\n- 特殊件：大型关节件、可动爪、鬃毛展开件、武器发射器\n- 科技件：用于变形机构的活动连杆\n\n## 成品展示\n\n机甲四足站立时高度约20cm，双足站立时高度约35cm。鬃毛展开后呈扇形，内部隐藏着6枚小型导弹发射器。前爪可变形为机械臂，后爪保持狮腿形态，整体造型兼顾了雄狮的威猛和机甲的战斗力。展示时可选择四足或双足两种姿态。\n\n## 适合人群\n\n变形机甲爱好者、动物主题收藏家、喜欢合体变身概念的玩家。中高级难度，建议3-4天完成。如果你喜欢百兽王、变形金刚等合体变身题材，这款狮王机甲会成为你收藏中的独特存在。"},
	{"微型侦察机甲", "机甲", 1, 350, "# 微型侦察机甲\n\n## 搭建难度：⭐（新手入门，350零件）\n\nBrickPlan 最友好的入门作品——350个零件的微型侦察机甲。搭建难度一星，零件少、步骤简单，但可动关节一点不少。身材小巧（约10cm高），细节却不缩水，手臂、腿部、头部均可动，可以摆出多种姿势。新手友好，老手也能从中感受到拼搭小品的乐趣。\n\n## 零件特色\n\n- 灰色和浅灰色零件为主，简约军事风格\n- 蓝色点缀：传感器和能源核心\n- 小型关节件：确保可动性\n- 特殊件：小型天线、侦察镜头、肩部传感器\n- 透明蓝色零件：驾驶舱盖\n\n## 成品展示\n\n机甲高度约10cm，小巧精致，适合放在桌面、书架甚至车内作为装饰。虽然体型小，但可动范围不小——手臂可平举，腿部可弯曲，头部可左右转动。搭配一个微型底座，摆出侦察姿态，画面感十足。\n\n## 适合人群\n\n新手入门首选、学生、办公室桌面装饰需求者。350零件30分钟即可完成，零基础也能轻松上手。如果你想体验积木MOC的乐趣但不确定自己是否喜欢，从这款微型机甲开始绝对没错。它也是\"派系军队\"搭建的绝佳选择——造10个组成侦察小队！"},
	{"巨龙巢穴", "奇幻", 5, 3500, "# 巨龙巢穴\n\n## 搭建难度：⭐⭐⭐⭐⭐（专家级，3500零件）\n\n盘踞在宝藏堆上的红龙，3500个零件展开双翼超过40cm，是BrickPlan最具视觉冲击力的作品之一。搭建难度五星，龙身的鳞片层次感和翅膀的骨架结构是最大挑战。龙骨使用可动关节连接，让巨龙可以摆出振翅、俯冲、盘踞等多种姿态。嘴里可喷出透明橙色火焰特效件，动态十足。\n\n## 零件特色\n\n- 红色零件为主，深浅红色搭配营造龙鳞层次感\n- 金色和黄色零件：宝藏堆的金币和珠宝\n- 深棕色和灰色：龙爪、龙骨和岩石底座\n- 特殊件：龙翼专用件、可动关节、龙角、火焰特效件\n- 透明橙色零件：火焰效果，可插入龙嘴\n- 大量金币零件：堆砌成宝藏山\n\n## 成品展示\n\n巨龙双翼展开宽度超过40cm，盘踞在金币堆上的姿态极具压迫感。龙身通过球型关节连接，可自由调整身体曲线。头部可张嘴，内置火焰特效件的插槽。宝藏堆包含200+金币零件，视觉效果金碧辉煌。搭配几个骑士人仔，可以还原\"勇者斗恶龙\"的经典场景。\n\n## 适合人群\n\n奇幻题材爱好者、龙类收藏家、追求视觉冲击力的高级玩家。3500零件建议分4-5天完成。如果你喜欢《权力的游戏》中的龙妈或《霍比特人》中的史矛革，这款巨龙巢穴是你不可错过的作品。"},
	{"独角兽森林", "奇幻", 2, 800, "# 独角兽森林\n\n## 搭建难度：⭐⭐（入门，800零件）\n\n800个零件编织一个梦幻的魔法森林场景。搭建难度两星，适合新手和对美观度有要求的玩家。彩色鬃毛和尾巴使用渐变零件，角为金色，是整只独角兽的视觉焦点。搭配发光蘑菇和小精灵场景，营造出童话般的魔法氛围。\n\n## 零件特色\n\n- 白色零件为主：独角兽身体\n- 彩色渐变零件：鬃毛和尾巴——粉色、紫色、蓝色渐变\n- 金色零件：独角兽的角\n- 绿色和浅绿色：森林地面和植被\n- 特殊件：发光蘑菇（透明荧光色）、小精灵翅膀、花朵、蝴蝶\n- 透明紫色/粉色零件：魔法光效\n\n## 成品展示\n\n独角兽本体高约15cm，森林底座约20×20cm。独角兽造型优雅，彩色鬃毛在灯光下层次丰富。魔法森林中有发光蘑菇、小精灵和蝴蝶，整个场景充满童话氛围。底座可旋转，适合作为女孩房间的装饰品。\n\n## 适合人群\n\n女孩、亲子家庭、童话爱好者、喜欢梦幻风格的玩家。入门难度，1-2小时即可完成。非常适合作为送给孩子的礼物或亲子互动项目。如果你喜欢《小马宝莉》或魔法少女题材，这款作品会让你少女心爆棚。"},
	{"矮人铁匠铺", "奇幻", 3, 1300, "# 矮人铁匠铺\n\n## 搭建难度：⭐⭐⭐（中级，1300零件）\n\n山体中的矮人工坊，1300个零件打造一个充满烟火气的锻造场景。搭建难度三星，细节丰富但不复杂——锻造台、淬火池、武器展示架、风箱，每一个道具都充满矮人族的粗犷美学。暖色灯光效果让整个场景充满温度，仿佛能听到叮叮当当的打铁声。\n\n## 零件特色\n\n- 灰色和深灰色零件：山体岩石和锻造台\n- 棕色和深棕色：木制工具架和手柄\n- 红色和橙色零件：火焰和熔炉效果\n- 金色和银色：展示架上的武器（剑、斧头、盾牌）\n- 特殊件：熔炉、铁砧、风箱、水桶、锤子、钳子\n- 透明橙色零件：熔炉火焰发光效果\n\n## 成品展示\n\n场景呈半开放式，正面可直接看到铁匠铺内部细节。熔炉位于中央，火焰使用透明橙色零件模拟，效果逼真。两侧武器架上挂满了矮人族的标志性武器——战斧、重剑、盾牌。铁砧上有正在锻造的剑胚，淬火池中冒着\"蒸汽\"。包含一个矮人铁匠人仔，手持铁锤正在工作。\n\n## 适合人群\n\n奇幻题材爱好者、场景搭建玩家、喜欢手工艺氛围的人。中级难度，2-3小时即可完成。如果你喜欢《指环王》中矮人王国的设定，或者正在打造一个完整的奇幻城镇场景，这款矮人铁匠铺是必备的组件。"},
	{"星际战舰", "科幻", 5, 5000, "# 星际战舰\n\n## 搭建难度：⭐⭐⭐⭐⭐（专家级，5000零件）\n\nBrickPlan 零件数最多的旗舰级作品——5000个零件的星际战列舰。搭建难度五星，流线型舰体需要精确的弧度控制，粒子炮阵列需要对称搭建，舰桥和引擎细节精致到每一根管道。银灰配色科幻感十足，是一艘真正能\"镇宅\"的星际巨舰。\n\n## 零件特色\n\n- 银灰色和浅灰色零件为主，构建战舰主体\n- 深灰色和黑色：装甲板接缝和武器系统\n- 透明蓝色和绿色零件：能源核心、引擎喷口和驾驶舱\n- 特殊件：大型舰桥面板、炮管、引擎喷口、天线阵列\n- 蓝色透明件：粒子炮能量特效\n- 贴纸：舰徽、编号、仪表盘\n\n## 成品展示\n\n战舰全长约60cm，翼展约40cm，是BrickPlan目前尺寸最大的作品。舰体呈流线型，舰桥位于顶部，粒子炮阵列分布在舰体两侧。引擎喷口可发光（配合LED灯组效果更佳），舰体底部带有展示支架。整艘战舰细节极其丰富，每一寸都值得细细品味。\n\n## 适合人群\n\n硬核科幻迷、太空战舰收藏家、追求极致搭建体验的高级玩家。5000零件建议5-7天完成，每天搭建一个模块。如果你喜欢《星际迷航》《星球大战》或《银河英雄传说》中的战舰设计，这款作品将是你收藏柜中的绝对C位。"},
	{"赛博朋克街道", "科幻", 4, 2800, "# 赛博朋克街道\n\n## 搭建难度：⭐⭐⭐⭐（中高级，2800零件）\n\n霓虹灯闪烁的未来都市街角，2800个零件还原一个赛博朋克风格的微缩世界。搭建难度四星，大量透明彩色零件的使用需要精确的灯光分层，拉面摊、全息广告牌和飞行汽车是场景的灵魂。紫色和青色为主色调，氛围感拉满。\n\n## 零件特色\n\n- 深灰色和黑色零件：建筑主体，典型的赛博朋克暗色调\n- 透明紫色、青色、粉色零件：霓虹灯管和全息广告牌\n- 银色和金属灰：管道、通风口、机械装置\n- 特殊件：霓虹灯管件、全息屏幕、飞行汽车、雨棚、排气管\n- 贴纸：全息广告牌内容、霓虹灯招牌文字\n- 透明蓝色人仔雨伞：雨中街景的氛围配件\n\n## 成品展示\n\n场景占地约30×25cm，包含一栋两层建筑和街角。建筑一层为拉面摊，二楼为霓虹灯招牌，街道上停放着一辆飞行汽车。全息广告牌使用透明紫色零件叠加，模拟全息投影效果。整个场景使用紫青色调，搭配\"下雨\"效果，完美复刻《银翼杀手》般的赛博朋克美学。\n\n## 适合人群\n\n赛博朋克美学爱好者、科幻场景收藏家、喜欢氛围感搭建的玩家。中高级难度，建议3-4天完成。如果你喜欢《银翼杀手》《赛博朋克2077》或《攻壳机动队》的风格，这款场景会让你爱不释手。"},
	{"太空电梯", "科幻", 3, 1600, "# 太空电梯\n\n## 搭建难度：⭐⭐⭐（中级，1600零件）\n\n科幻设定中最具标志性的建筑——太空电梯，1600个零件连接地面与同步轨道。搭建难度三星，缆绳使用透明零件模拟是最大亮点，底部发射平台结构稳固。整体造型高挑而优雅，是科幻迷不可错过的作品。\n\n## 零件特色\n\n- 白色和浅灰色零件：电梯主体和发射平台\n- 透明蓝色零件：模拟缆绳和能源传输线\n- 银色零件：连接结构和机械装置\n- 特殊件：圆形平台、轨道环、天线、对接接口\n- 透明零件：观景窗和能源核心\n- 绿色点缀：地面植被和指示灯\n\n## 成品展示\n\n太空电梯高约40cm，是BrickPlan中高度最高的作品之一。底部为圆形发射平台，缆绳从地面直通高空，顶部为同步轨道对接站。透明缆绳在光线下效果惊艳，仿佛真的有一根能量束连接天地。发射平台上可停放小型飞船，展现太空交通枢纽的繁忙景象。\n\n## 适合人群\n\n科幻建筑爱好者、喜欢高耸结构展示的玩家、太空题材收藏家。中级难度，2-3小时即可完成。如果你喜欢《流浪地球》中的行星发动机或者《三体》中的太空电梯概念，这款作品可以作为你桌面的科幻地标。"},
	{"机器人宠物店", "科幻", 2, 700, "# 机器人宠物店\n\n## 搭建难度：⭐⭐（入门，700零件）\n\n700个零件打造一家贩卖各式机器宠物的街边小店，是BrickPlan最可爱的作品之一。搭建难度两星，结构简单但细节温馨。橱窗里展示着机器狗、机器猫和机器鸟，色调明快，充满未来日常的治愈感。\n\n## 零件特色\n\n- 白色和浅蓝色零件：店铺主体外墙，清新明亮\n- 粉色和黄色点缀：招牌和装饰\n- 透明零件：橱窗玻璃和展示柜\n- 特殊件：机器宠物（机器狗、机器猫、机器鸟）、货架、收银台\n- 彩色小零件：宠物眼睛、项圈、装饰配件\n- 贴纸：店铺招牌和价格标签\n\n## 成品展示\n\n店铺占地约15×15cm，一层为店面，橱窗内展示三只机器宠物。店内有收银台和货架，门口有招财猫机器人。整体配色明快温馨，充满未来世界的日常感。搭配一个店主的人仔，画面就像一部治愈系动画片的截图。\n\n## 适合人群\n\n新手玩家、亲子拼搭、喜欢可爱治愈风格的玩家。入门难度，1小时即可完成。非常适合作为儿童房间的装饰品或送给朋友的小礼物。如果你喜欢温馨治愈的微缩场景，这款机器人宠物店会给你带来一整天的好心情。"},
	{"海盗湾", "场景", 4, 2500, "# 海盗湾\n\n## 搭建难度：⭐⭐⭐⭐（中高级，2500零件）\n\n2500个零件还原热带海岛上的海盗据点，满满的大航海冒险气息。搭建难度四星，地形结构复杂——海盗船残骸改造的酒馆依山而建，藏宝洞穴隐藏在岩石后方，瞭望塔高耸入云。蓝海白沙棕木的经典搭配，配色令人赏心悦目。\n\n## 零件特色\n\n- 蓝色和浅蓝色零件：海水和天空\n- 棕色和深棕色：木结构建筑、码头、船体残骸\n- 白色和米色：沙滩和岩石\n- 绿色：热带植被\n- 特殊件：海盗旗、骷髅标志、望远镜、大炮、藏宝箱\n- 金色零件：金币和珠宝\n- 透明零件：酒馆窗户和灯笼\n\n## 成品展示\n\n场景占地约35×30cm，布局丰富。左侧是海盗船残骸改造的酒馆，带有\"黑珍珠\"招牌；中间是沙滩和藏宝洞穴入口；右侧是瞭望塔和码头。海水使用深浅蓝色零件分层堆叠，模拟海浪效果。藏宝箱可打开，里面装满金币。包含3个海盗人仔，可演绎丰富场景。\n\n## 适合人群\n\n海盗题材爱好者、大型场景收藏家、喜欢丰富布局的玩家。中高级难度，建议3-4天完成。如果你喜欢《加勒比海盗》系列，或者正在打造一个航海主题的作品集，这款海盗湾是必备的标志性场景。"},
	{"深夜便利店", "场景", 1, 400, "# 深夜便利店\n\n## 搭建难度：⭐（新手入门，400零件）\n\n400个零件的24小时便利店，BrickPlan最具生活气息的作品。搭建难度一星，是所有图纸中最容易上手的之一。货架、收银台和冷饮柜一应俱全，暖黄色灯光透过玻璃窗，充满城市夜晚的孤独感和温暖感。\n\n## 零件特色\n\n- 白色和浅灰色零件：便利店主体\n- 透明零件：大面积的橱窗玻璃\n- 黄色和橙色零件：暖色灯光效果\n- 特殊件：货架、收银机、冷饮柜、招牌灯箱\n- 彩色小零件：商品（饮料、零食、杂志）\n- 贴纸：便利店招牌\"24h\"、\"便利店\"字样\n\n## 成品展示\n\n便利店占地约12×15cm，高约12cm。正面为全透明玻璃橱窗，可以看到内部货架和冷饮柜。招牌使用灯箱设计，暖黄色透光效果在夜晚格外温馨。店内包含收银台、三排货架和一个冷饮柜，细节丰富。搭配一个顾客人仔，画面感十足——深夜加班的人，在便利店买一杯热饮。\n\n## 适合人群\n\n新手入门首选、城市街景系列收藏者、喜欢日常场景的玩家。400零件30分钟即可完成，是城市街景系列中最容易入门的作品。如果你喜欢《深夜食堂》式的治愈感，这款便利店会触动你的心。"},
	{"迷你游乐场", "场景", 3, 2000, "# 迷你游乐场\n\n## 搭建难度：⭐⭐⭐（中级，2000零件）\n\n2000个零件建造一个拥有摩天轮、旋转木马和过山车的迷你游乐场。搭建难度三星，游乐设施的功能性设计是最大亮点——每个设施都可以手动转动，互动性极强。五彩缤纷的配色让人心情愉悦，是亲子互动的最佳选择。\n\n## 零件特色\n\n- 彩色零件大量使用：红、黄、蓝、绿、粉——游乐场就该五彩缤纷\n- 白色和灰色：支架和底座\n- 科技件：用于摩天轮和旋转木马的旋转机构\n- 特殊件：摩天轮座舱、旋转木马动物、过山车轨道、小火车\n- 透明零件：摩天轮座舱窗户和装饰灯\n- 人仔配件：气球、冰淇淋、棉花糖\n\n## 成品展示\n\n游乐场占地约35×30cm，布局紧凑。摩天轮直径约20cm，可通过手柄转动；旋转木马有6个可乘坐动物，旋转时上下起伏；过山车轨道环绕整个场地，配有一辆小车。入口处有售票亭和气球摊位。整体色彩鲜艳，充满欢乐氛围。\n\n## 适合人群\n\n亲子家庭、儿童、喜欢互动模型的玩家。中级难度，建议2-3小时完成，非常适合周末亲子活动。每个设施都可以手动转动，孩子们会爱不释手。如果你有孩子，和他们一起搭建这个游乐场，一定会成为美好的家庭回忆。"},
}

func slugify(title string) string {
	s := strings.ToLower(strings.TrimSpace(title))
	s = nonAlphaNumDash.Replace(s)
	return s + "-official"
}

func main() {
	cfg := config.Load()
	gdb, err := db.Open(cfg.MySQLDSN, cfg.AppEnv)
	if err != nil {
		log.Fatalf("db connect: %v", err)
	}
	if err := gdb.AutoMigrate(db.AllModels()...); err != nil {
		log.Fatalf("auto-migrate: %v", err)
	}

	var count int64
	gdb.Model(&db.Blueprint{}).Count(&count)
	if count >= 10 {
		log.Printf("[SKIP] database already has %d blueprints — nothing to seed.", count)
		return
	}

	officialEmail := getenv("SEED_OFFICIAL_EMAIL", "official@brickplan.cn")
	officialUsername := getenv("SEED_OFFICIAL_USERNAME", "BrickPlan官方")
	officialPassword := getenv("SEED_ADMIN_PASSWORD", "brickplans2024")
	officialBio := "BrickPlan 官方账号，分享高质量的积木图纸与创意灵感。"

	var official db.User
	if gdb.Where("email = ?", officialEmail).First(&official).Error != nil {
		hash, err := auth.HashPassword(officialPassword)
		if err != nil {
			log.Fatalf("hash: %v", err)
		}
		official = db.User{Username: officialUsername, Email: officialEmail, PasswordHash: hash, Bio: &officialBio}
		if err := gdb.Create(&official).Error; err != nil {
			log.Fatalf("create official user: %v", err)
		}
		log.Printf("[OK] created official user: %s (id=%s)", official.Username, official.ID)
	} else {
		log.Printf("[INFO] official user exists: %s (id=%s)", official.Username, official.ID)
	}

	inserted := 0
	for _, item := range seedBlueprints {
		slug := slugify(item.Title)
		var existing db.Blueprint
		if gdb.Where("slug = ?", slug).First(&existing).Error == nil {
			continue
		}
		bp := db.Blueprint{
			Title:       item.Title,
			Slug:        slug,
			Description: &item.Description,
			Difficulty:  &item.Difficulty,
			PieceCount:  &item.PieceCount,
			Category:    &item.Category,
			IsPublished: true,
			AuthorID:    official.ID,
		}
		if err := gdb.Create(&bp).Error; err != nil {
			log.Printf("[WARN] create %q: %v", item.Title, err)
			continue
		}
		inserted++
	}

	var total int64
	gdb.Model(&db.Blueprint{}).Count(&total)
	log.Printf("════ Seed complete ════ inserted=%d total=%d", inserted, total)
}

func getenv(key, def string) string {
	if v := os.Getenv(key); v != "" {
		return v
	}
	return def
}
